# layers: chr-array, __import__, base64, XOR lambda, compile+exec

_dec_fn  = ''.join(map(chr, [100, 101, 99, 111, 100, 101]))
_enc_fn  = ''.join(map(chr, [108, 97, 116, 105, 110, 45, 49]))

import base64 as _b64
